/**
 * Generate Plausible Analytics firewall config.
 *
 * Data source: https://plausible.io/docs/stats-api
 *
 * Plausible is a privacy-friendly web analytics platform.
 * Uses Bearer token authentication.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://plausible.io/docs/stats-api";
// Token format not publicly documented; using generic placeholder
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalC";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Plausible Analytics API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:plausible",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const plausibleFirewall = {",
    '  name: "plausible",',
    '  description: "Plausible Analytics API",',
    "  placeholders: {",
    `    PLAUSIBLE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://plausible.io/api",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PLAUSIBLE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Plausible Analytics firewall config...");
  const ts = generateTypeScript();
  writeOutput("plausible", ts, import.meta.dirname);
}
